-- ----------------------------
-- Table structure for post
-- ----------------------------
DROP TABLE IF EXISTS `post`;
CREATE TABLE `post`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '图片路径JSON数组(兼容逗号分隔旧格式)',
  `category` tinyint NULL DEFAULT 1 COMMENT '1:表白, 2:寻物, 3:闲置, 4:吐槽, 5:活动',
  `is_anonymous` tinyint(1) NULL DEFAULT 0 COMMENT '1:匿名',
  `visibility` tinyint(1) NULL DEFAULT 0 COMMENT '0:公开, 1:仅自己',
  `end_time` datetime NULL DEFAULT NULL COMMENT '活动结束时间',
  `view_count` int NULL DEFAULT 0,
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '0:待审, 1:通过, 2:驳回',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `reward` decimal(10, 2) NULL DEFAULT 0.00,
  `deadline` datetime NULL DEFAULT NULL,
  `like_count` int NULL DEFAULT 0 COMMENT '点赞数',
  `comment_count` int NULL DEFAULT 0 COMMENT '评论数',
  `share_count` int NULL DEFAULT 0 COMMENT '分享数',
  `poll_options` json NULL COMMENT '投票选项JSON',
  `poll_end_time` datetime NULL DEFAULT NULL COMMENT '投票截止时间',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签JSON数组',
  `scheduled_time` datetime NULL DEFAULT NULL COMMENT '定时发布时间',
  `location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '地理位置',
  `video` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '视频地址',
  `is_ai_assisted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否使用AI润色',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_post_status_time`(`status` ASC, `create_time` DESC) USING BTREE,
  INDEX `idx_post_category`(`category` ASC) USING BTREE,
  INDEX `idx_post_user`(`user_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 84 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

