-- ----------------------------
-- Table structure for story
-- ----------------------------
DROP TABLE IF EXISTS `story`;
CREATE TABLE `story`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '故事ID',
  `title` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '故事标题',
  `category` tinyint NOT NULL COMMENT '分类: 1奇幻校园 2悬疑推理 3浪漫物语 4搞笑日常 5科幻未来',
  `world_setting` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '世界观设定',
  `first_paragraph` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '开篇内容',
  `creator_id` bigint NOT NULL COMMENT '创建者ID',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态: 1进行中 2已完结 3已归档',
  `paragraph_count` int NULL DEFAULT 1 COMMENT '段落数量',
  `participant_count` int NULL DEFAULT 1 COMMENT '参与人数',
  `total_likes` int NULL DEFAULT 0 COMMENT '总点赞数',
  `is_recommended` tinyint NULL DEFAULT 0 COMMENT '是否官方推荐',
  `finish_vote_id` bigint NULL DEFAULT NULL COMMENT '当前完结投票ID',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `finish_time` datetime NULL DEFAULT NULL COMMENT '完结时间',
  `editing_user_id` bigint NULL DEFAULT NULL COMMENT '当前正在编辑的用户ID',
  `editing_expire_time` datetime NULL DEFAULT NULL COMMENT '编辑锁过期时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_story_category`(`category` ASC) USING BTREE,
  INDEX `idx_story_status`(`status` ASC) USING BTREE,
  INDEX `idx_story_creator`(`creator_id` ASC) USING BTREE,
  INDEX `idx_story_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1001 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '故事主表' ROW_FORMAT = DYNAMIC;

