-- ----------------------------
DROP TABLE IF EXISTS `story_finish_vote`;
CREATE TABLE `story_finish_vote`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '投票ID',
  `story_id` bigint NOT NULL COMMENT '故事ID',
  `initiator_id` bigint NOT NULL COMMENT '发起者ID',
  `agree_count` int NULL DEFAULT 0 COMMENT '同意数',
  `disagree_count` int NULL DEFAULT 0 COMMENT '反对数',
  `total_voters` int NOT NULL COMMENT '有投票权的总人数',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态: 1进行中 2已通过 3已否决 4已过期',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `expire_time` datetime NOT NULL COMMENT '过期时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_vote_story`(`story_id` ASC) USING BTREE,
  CONSTRAINT `fk_vote_story` FOREIGN KEY (`story_id`) REFERENCES `story` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '完结投票表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of story_finish_vote
-- ----------------------------

-- ----------------------------
-- Table structure for story_finish_vote_record
-- ----------------------------
DROP TABLE IF EXISTS `story_finish_vote_record`;
CREATE TABLE `story_finish_vote_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `vote_id` bigint NOT NULL COMMENT '投票ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `agree` tinyint NOT NULL COMMENT '是否同意: 1同意 0反对',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '投票时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_vote_record_vote_user`(`vote_id` ASC, `user_id` ASC) USING BTREE,
  CONSTRAINT `fk_vote_record_vote` FOREIGN KEY (`vote_id`) REFERENCES `story_finish_vote` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '完结投票记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of story_finish_vote_record
-- ----------------------------

-- ----------------------------
-- Table structure for story_paragraph
-- ----------------------------
DROP TABLE IF EXISTS `story_paragraph`;
CREATE TABLE `story_paragraph`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '段落ID',
  `story_id` bigint NOT NULL COMMENT '故事ID',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '段落内容',
  `image_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '插画URL',
  `author_id` bigint NOT NULL COMMENT '作者ID',
  `pen_name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '笔名',
  `sequence` int NOT NULL COMMENT '段落序号',
  `like_count` int NULL DEFAULT 0 COMMENT '点赞数',
  `is_hot` tinyint NULL DEFAULT 0 COMMENT '是否热门(点赞>10)',
  `is_key_point` tinyint NULL DEFAULT 0 COMMENT '是否关键转折点(点赞>50或作者标记)',
  `is_author_marked` tinyint NULL DEFAULT 0 COMMENT '是否作者标记为关键点',
  `parent_id` bigint NULL DEFAULT NULL COMMENT '父段落ID(用于分支)',
  `branch_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分支名称',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_ai_assisted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否使用AI润色',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_story_sequence`(`story_id` ASC, `sequence` ASC) USING BTREE,
  INDEX `idx_paragraph_story`(`story_id` ASC) USING BTREE,
  INDEX `idx_paragraph_author`(`author_id` ASC) USING BTREE,
  CONSTRAINT `fk_paragraph_story` FOREIGN KEY (`story_id`) REFERENCES `story` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 10012 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '故事段落表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of story_paragraph
-- ----------------------------

-- ----------------------------
-- Table structure for story_read_progress
-- ----------------------------
DROP TABLE IF EXISTS `story_read_progress`;
CREATE TABLE `story_read_progress`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `story_id` bigint NOT NULL COMMENT '故事ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `last_read_sequence` int NULL DEFAULT 0 COMMENT '最后阅读的段落序号',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_read_story_user`(`story_id` ASC, `user_id` ASC) USING BTREE,
  CONSTRAINT `fk_read_story` FOREIGN KEY (`story_id`) REFERENCES `story` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '故事阅读进度表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of story_read_progress
-- ----------------------------

