-- Table structure for sys_punishment
-- ----------------------------
DROP TABLE IF EXISTS `sys_punishment`;
CREATE TABLE `sys_punishment`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '被罚人',
  `type` tinyint(1) NOT NULL COMMENT '1:扣分 2:封号',
  `score_deducted` int NULL DEFAULT 0 COMMENT '扣分数',
  `duration_days` int NULL DEFAULT 0 COMMENT '封号天数(记录用)',
  `reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

