-- Table structure for sys_sensitive
-- ----------------------------
DROP TABLE IF EXISTS `sys_sensitive`;
CREATE TABLE `sys_sensitive`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `word` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '敏感词',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_word`(`word` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 46 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_sensitive
-- ----------------------------

-- ----------------------------
-- Table structure for sys_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `account` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '账号(学号/手机)',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '密码',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '昵称(代码中设置为张院+后4位)',
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '/files/default.png' COMMENT '头像(本地路径)',
  `signature` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '个性签名',
  `role` tinyint(1) NULL DEFAULT 0 COMMENT '0:用户, 1:管理员',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '1:正常, 0:禁言/封号',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `ban_end_time` datetime NULL DEFAULT NULL COMMENT '封禁截止时间',
  `credit_score` int NULL DEFAULT 100 COMMENT '信誉分',
  `violation_count` int NULL DEFAULT 0 COMMENT '违规次数',
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '/files/default_cover.jpg' COMMENT '个人主页封面',
  `last_nickname_update` datetime NULL DEFAULT NULL COMMENT '上次修改昵称时间',
  `last_active_time` datetime NULL DEFAULT NULL COMMENT '最后离线时间',
  `following_count` int NULL DEFAULT 0 COMMENT '关注数',
  `followers_count` int NULL DEFAULT 0 COMMENT '粉丝数',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_account`(`account` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 137 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_user
-- ----------------------------

-- ----------------------------
-- Table structure for sys_visitor
-- ----------------------------
DROP TABLE IF EXISTS `sys_visitor`;
CREATE TABLE `sys_visitor`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '被访问者(主人)',
  `visitor_id` bigint NOT NULL COMMENT '访问者(客人)',
  `visit_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '访问时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_visit`(`user_id` ASC, `visit_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '访客记录表' ROW_FORMAT = DYNAMIC;

