INSERT INTO `drift_bottle` VALUES (1, 3, '今天在图书馆看到一个很可爱的女生，想认识她但不敢上前，希望这个瓶子能飘到她那里。', 1, 1, 1, 0, '2025-12-19 16:23:57', '2025-12-26 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (2, 5, '大学四年快结束了，有些话一直没说出口。如果时光能倒流，我一定会勇敢一点。', 1, 1, 3, 0, '2025-12-16 16:23:57', '2025-12-23 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (3, 7, '食堂三楼的那个学姐，你的笑容真的很治愈，每次看到你我的心情都会变好。', 1, 1, 3, 0, '2025-12-20 16:23:57', '2025-12-27 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (4, 2, '有时候觉得很孤独，想找个人说说话，但又不知道该对谁说。', 2, 1, 1, 0, '2025-12-18 16:23:57', '2025-12-25 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (5, 6, '最近压力好大，考试、论文、实习...感觉快要撑不住了。希望捡到这个瓶子的人能给我一些鼓励。', 2, 1, 5, 0, '2025-12-17 16:23:57', '2025-12-24 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (6, 4, '深夜emo时刻：为什么越长大越孤单？想念小时候无忧无虑的日子。', 2, 1, 1, 0, '2025-12-21 14:23:57', '2025-12-27 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (7, 3, '梦想是成为一名优秀的程序员，希望毕业后能进入大厂工作！加油！', 3, 1, 1, 0, '2025-12-20 16:23:57', '2025-12-27 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (8, 5, '想去看看外面的世界，想去西藏、想去新疆、想去所有美丽的地方。', 3, 1, 2, 0, '2025-12-15 16:23:57', '2025-12-22 16:23:57', 0);
INSERT INTO `drift_bottle` VALUES (9, 7, '希望毕业后能找到一份自己喜欢的工作，不为钱，只为热爱。', 3, 1, 3, 0, '2025-12-21 13:23:57', '2025-12-27 16:23:57', 0);
