INSERT INTO `post` VALUES (7, 3, '嘿，朋友们，第一次在这里写下这些字，心里还真有点小小的紧张呢。就像推开一扇陌生的门，不知道门后会是怎样的风景。指尖在键盘上停留了片刻，终于还是鼓起勇气，让这些文字轻轻落在屏幕上。希望从今天起，能在这里遇见温暖的故事，和有趣的灵魂。', '', 9, 0, 0, NULL, 12, 1, '2025-12-10 22:47:43', NULL, NULL, 5, 10, 0, NULL, NULL, '[\"吐槽\"]', NULL, '紫荆园 附近', '', 0);
