INSERT INTO `story` VALUES (1, '图书馆的秘密', 1, '在张家界学院的图书馆深处，隐藏着一扇通往异世界的门。只有在午夜12点，持有特殊借书证的学生才能看到它。', '那是一个普通的周五晚上，我像往常一样在图书馆复习到深夜。当时钟指向午夜12点时，我突然发现书架后面透出一道奇异的光芒...', 3, 1, 5, 3, 12, 1, NULL, '2025-12-16 16:23:57', '2025-12-21 16:23:57', NULL, NULL, NULL);
INSERT INTO `story` VALUES (2, '银杏树下的约定', 3, '张家界学院有一棵百年银杏树，传说在银杏叶飘落的季节，在树下许下的愿望都会实现。', '秋天来了，校园里的银杏树又黄了。我站在树下，看着金黄的叶子随风飘落，想起了三年前的那个约定...', 2, 1, 10, 7, 9, 1, NULL, '2025-12-17 16:23:57', '2026-01-28 23:29:01', NULL, 59, '2026-04-06 21:18:49');
INSERT INTO `story` VALUES (3, '食堂大冒险', 4, '张家界学院的食堂是一个神奇的地方，每天都会发生各种搞笑的事情。', '今天中午，我像往常一样去食堂吃饭。没想到，这将是我人生中最难忘的一顿午餐...', 4, 1, 3, 2, 5, 0, NULL, '2025-12-18 16:23:57', '2025-12-21 16:23:57', NULL, NULL, NULL);
INSERT INTO `story` VALUES (1000, '张家界学院的奇幻冒险', 1, '在张家界学院的深处，隐藏着一个连接异世界的神秘传送门。只有在月圆之夜，拥有纯净心灵的学生才能看见它的存在。', '那是一个普通的秋日午后，图书馆三楼的阳光透过落地窗洒在古旧的书架上。我正在查阅关于学院历史的资料，突然发现了一本没有标题的羊皮书。当我翻开第一页时，书页上浮现出金色的文字：\"寻找月光之门的勇士啊，你的冒险即将开始...\"就在这时，整个图书馆开始轻微震动，书架后面传来了神秘的光芒。', 3, 2, 4, 15, 156, 1, 1000, '2025-12-01 14:30:00', '2025-12-21 17:21:29', '2025-12-15 20:45:00', NULL, NULL);
