INSERT INTO `story_favorite` VALUES (1, 1, 5, '2025-12-17 16:23:57');
INSERT INTO `story_favorite` VALUES (2, 1, 7, '2025-12-18 16:23:57');
INSERT INTO `story_favorite` VALUES (3, 2, 3, '2025-12-18 16:23:57');
INSERT INTO `story_favorite` VALUES (4, 2, 4, '2025-12-19 16:23:57');
INSERT INTO `story_paragraph` VALUES (1, 1, '那是一个普通的周五晚上，我像往常一样在图书馆复习到深夜。当时钟指向午夜12点时，我突然发现书架后面透出一道奇异的光芒...', NULL, 3, '夜行者', 1, 3, 0, 0, 0, NULL, NULL, '2025-12-16 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (2, 1, '我小心翼翼地走近那道光芒，发现书架后面竟然有一扇门！门上刻着古老的符文，散发着淡淡的蓝光。我犹豫了一下，还是推开了那扇门...', NULL, 5, '探险家', 2, 5, 0, 0, 0, NULL, NULL, '2025-12-17 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (3, 1, '门后是一个完全不同的世界！天空是紫色的，飘浮着发光的水晶。远处有一座巨大的城堡，城堡周围环绕着会飞的书本。一个穿着长袍的老人向我走来：\"欢迎来到知识之境，年轻的学者。\"', NULL, 7, '幻想师', 3, 2, 0, 0, 0, NULL, NULL, '2025-12-18 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (4, 1, '老人告诉我，这里是所有知识的源泉。每一本飞舞的书都代表着人类历史上的一个重要发现。但最近，有邪恶的力量想要摧毁这个世界，我必须找到三把钥匙来拯救它。', NULL, 5, '探险家', 4, 1, 0, 0, 0, NULL, NULL, '2025-12-19 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (5, 1, '第一把钥匙藏在\"勇气之塔\"的顶端。我深吸一口气，开始了我的冒险之旅。塔内充满了各种机关和谜题，每一步都需要运用我在学校学到的知识...', NULL, 3, '夜行者', 5, 1, 0, 0, 0, NULL, NULL, '2025-12-20 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (6, 2, '秋天来了，校园里的银杏树又黄了。我站在树下，看着金黄的叶子随风飘落，想起了三年前的那个约定...', NULL, 2, '秋叶', 1, 2, 0, 0, 0, NULL, NULL, '2025-12-17 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (7, 2, '那年我们都是大一新生，在迎新晚会上第一次见面。你穿着白色的连衣裙，笑起来眼睛弯弯的，像月牙一样。我们约定，三年后的今天，还要在这棵银杏树下相见。', NULL, 6, '回忆者', 2, 3, 0, 0, 0, NULL, NULL, '2025-12-18 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (8, 2, '但是现在，你已经去了另一个城市读研，我们已经很久没有联系了。我拿出手机，犹豫着要不要给你发消息。就在这时，一片银杏叶飘落在我的手机屏幕上...', NULL, 2, '秋叶', 3, 2, 0, 0, 0, NULL, NULL, '2025-12-19 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (9, 2, '我抬起头，看到一个熟悉的身影正向我走来。是你！你还是那样，笑起来眼睛弯弯的。\"对不起，我来晚了。\"你说。我笑了：\"不晚，刚刚好。\"', NULL, 6, '回忆者', 4, 1, 0, 0, 0, NULL, NULL, '2025-12-20 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (10, 3, '今天中午，我像往常一样去食堂吃饭。没想到，这将是我人生中最难忘的一顿午餐...', NULL, 4, '吃货小王', 1, 2, 0, 0, 0, NULL, NULL, '2025-12-18 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (11, 3, '排队打饭的时候，前面的同学突然转身，手里的餐盘直接飞了出去！汤汁在空中划出一道完美的抛物线，精准地落在了我的头上。全食堂的人都看着我，我尴尬地笑了笑：\"谢谢，我正想洗头呢。\"', NULL, 7, '倒霉蛋', 2, 2, 0, 0, 0, NULL, NULL, '2025-12-19 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (12, 3, '更搞笑的是，食堂阿姨看到我这副样子，居然免费给了我一份饭！她说：\"孩子，你太惨了，这顿饭阿姨请你！\"我瞬间觉得，这汤浇得值了！', NULL, 4, '吃货小王', 3, 1, 0, 0, 0, NULL, NULL, '2025-12-20 16:23:57', 0);
INSERT INTO `story_paragraph` VALUES (10001, 1000, '那是一个普通的秋日午后，图书馆三楼的阳光透过落地窗洒在古旧的书架上。我正在查阅关于学院历史的资料，突然发现了一本没有标题的羊皮书。当我翻开第一页时，书页上浮现出金色的文字：\"寻找月光之门的勇士啊，你的冒险即将开始...\"就在这时，整个图书馆开始轻微震动，书架后面传来了神秘的光芒。', NULL, 3, NULL, 1, 23, 1, 0, 0, NULL, NULL, '2025-12-01 14:30:00', 0);
INSERT INTO `story_paragraph` VALUES (10002, 1000, '我小心翼翼地走向光源，推开了那扇隐藏在书架后的暗门。门后是一条螺旋向下的石阶，墙壁上镶嵌着会发光的水晶，照亮了前行的道路。空气中弥漫着淡淡的薄荷香气，让人感到既紧张又兴奋。走了大约五分钟，我来到了一个巨大的地下空间，中央矗立着一座古老的石碑，上面刻着奇怪的符文。', NULL, 5, '夜行者', 2, 18, 1, 0, 0, NULL, NULL, '2025-12-01 16:45:00', 0);
INSERT INTO `story_paragraph` VALUES (10003, 1000, '当我伸手触碰石碑的瞬间，一股强大的能量涌入体内。脑海中突然出现了大量陌生的记忆——原来这座学院建立在一个古老魔法阵的遗址上，而我手中的羊皮书正是开启传送门的钥匙。石碑开始发出耀眼的蓝光，地面上浮现出复杂的魔法阵图案，一个巨大的光门在我面前缓缓打开。', NULL, 7, '星辰', 3, 31, 1, 0, 0, NULL, NULL, '2025-12-02 09:20:00', 0);
INSERT INTO `story_paragraph` VALUES (10004, 1000, '我深吸一口气，踏入了光门。眼前的景象让我震惊——这是一个完全不同的世界！天空呈现出梦幻般的紫色，三个月亮悬挂在空中，远处是连绵起伏的水晶山脉。更神奇的是，我发现自己身上的校服变成了一套银白色的法师长袍，手中多了一根散发着微光的法杖。', NULL, 3, '探险家', 4, 15, 1, 0, 0, NULL, NULL, '2025-12-02 20:15:00', 0);
INSERT INTO `story_paragraph` VALUES (10006, 2, '是你啊。我愣在原地，指尖还停在手机屏幕上，那些积攒了许久的问候突然都堵在喉咙里。午后的阳光斜斜地穿过走廊，在你发梢上镀了层薄薄的金边——这场景熟悉得让人恍惚，仿佛我们昨天才在这里道别。时间真是奇妙的东西，它能把记忆磨得温润，却也让重逢的瞬间变得小心翼翼。你过得好吗？这句话在我心里转了好几圈，最后出口时，竟带着点连自己都没察觉的叹息。', NULL, 18, '匿名作者', 5, 1, 0, 0, 0, NULL, NULL, '2026-01-19 12:53:20', 0);
INSERT INTO `story_paragraph` VALUES (10007, 2, '她轻轻开口，声音像被时光磨得温润的旧唱片：“这些年，我过得还算不错。”说完这句，她顿了顿，目光在我脸上停留了片刻，仿佛在辨认岁月留下的痕迹。然后，那声音又软软地飘过来，带着一丝小心翼翼的试探：“你呢？你……都好吗？”\n\n窗外的梧桐叶正一片片往下落，阳光穿过枝叶的缝隙，在她睫毛上投下细碎的影子。我忽然想起多年前的某个午后，她也曾这样问过我，只是那时的语气里还藏着少年人特有的莽撞与直白。如今这句话里，却多了些欲言又止的温柔，像秋日里最后一阵暖风，轻轻拂过心头。', NULL, 135, '匿名作者', 6, 0, 0, 0, 1, NULL, NULL, '2026-01-19 21:03:14', 0);
INSERT INTO `story_paragraph` VALUES (10008, 2, '那是一个寻常的午后，阳光斜斜地穿过教室的窗棂，在摊开的课本上投下斑驳的光影。粉笔灰在光束里缓缓浮沉，像极了时光的尘埃。我正对着数学题发呆，笔尖在草稿纸上无意识地画着圈，思绪早已飘到了窗外那棵正抽出新芽的梧桐树上。\n就在这时，一张折叠成方胜状的小纸条，轻轻落在了我\n\n我愣了一下，抬头望去。前排那个总是扎着马尾辫的背影，此刻正微微侧着，耳尖在阳光下透出淡淡的粉色。她的肩膀绷得有些紧，像是等待着什么。\n\n教室里很安静，只有风扇转动时发出的、规律的嗡嗡声。我屏住呼吸，用指尖小心翼翼地展开纸条。纸张很普通，是从笔记本上撕下来的横格页，边缘还带着些许毛糙。可上面那行清秀的字迹，却让我的心跳漏了一拍——\n\n“放学后，图书馆三楼的老地方，有话想对你说。”\n\n没有署名。但那一笔一划的认真劲儿，我认得。\n\n窗外的梧桐叶被风吹得沙沙作响，光影随之晃动，仿佛整个世界都跟着我的心跳轻轻摇晃起来。我悄悄将纸条合拢，握在手心。纸张的触感微凉，却似乎有什么温度，正从那里，一点点渗进我的血液里。\n\n讲台上，老师的声音忽然变得遥远。我低下头，假装继续演算那道未完成的习题，可笔尖下，不知不觉写出的，却是一个又一个她的名字。', NULL, 2, NULL, 7, 0, 0, 0, 0, NULL, NULL, '2026-01-28 23:28:34', 0);
INSERT INTO `story_paragraph` VALUES (10009, 2, '故事就这样悄然翻开了新的一页，像晨光里缓缓舒展的叶脉，带着湿润的、未干的露水气息。我站在这一行的末尾，笔尖悬停，仿佛能听见下一页空白的呼吸——轻而绵长，带着无限的可能。那些尚未落下的字句，像藏在云后的星光，等着被某一阵风、某一次心跳轻轻唤醒。而我会在这里，慢慢写下去，把时光纺成细密的线，织进每一个等待被讲述的明天里。', NULL, 10, NULL, 8, 0, 0, 0, 0, NULL, NULL, '2026-04-06 20:40:21', 0);
INSERT INTO `story_paragraph` VALUES (10010, 2, '\n\n黄昏时分，工作告一段落。保存文档时，我看着满屏的标注痕迹，忽然觉得这些蓝色的记号像极了读书时在页边写下的批注。只是从前是用铅笔，现在是用数据；从前是与过去的自己对话，现在是与未来的可能交谈。\n\n关掉软件前，我最后看了一眼那些标注。它们在渐暗的屏幕光里微微发亮，像是星图，标记着这次小小实验的轨迹——不是人与机器的对抗，而是两种理解世界的方式，在这个平凡的下午，轻轻碰撞，又各自延伸开去。\n\n而故事，大概就从这里真正开始了。', NULL, 46, NULL, 9, 0, 0, 0, 0, NULL, NULL, '2026-04-06 21:02:01', 0);
INSERT INTO `story_paragraph` VALUES (10011, 2, '嘿，你也在为那个故事卡壳发愁吗？我懂那种感觉——脑海里明明有万千星河在闪烁，落到纸上却只剩几颗疏落的星子，怎么都串不成动人的银河。\n\n有时候故事需要的不是情节的推进，而是某个瞬间的深度沉浸。就像电影里那些意味深长的空镜——雨滴在玻璃上蜿蜒的轨迹，旧书页边缘微微卷起的弧度，对话间隙窗外忽然掠过的飞鸟。这些细微之处往往比戏剧性的转折更能留住读者的呼吸。\n\n我最近常觉得，好的续写不是接上断掉的线，而是在断口处生长出新的枝桠。或许你的主角并没有走向预设的命运岔路，而是停在半途，听见了从前未曾留意的声音：童年故居后院的蝉鸣，离别时未被说出口的某个音节，甚至只是自己心跳在寂静中的回响。\n\n要不要试着把笔交给故事本身？别急着掌控它，而是跟随它去往未曾预料的深处。相信你创造的那个世界自有其生命力，而你所要做的，只是成为最专注的聆听者和记录者。\n\n期待读到只属于你的、带着体温的故事续章。它不必完美，但一定真挚——就像深夜分享给好友的语音消息，有些断续，有些即兴，却因为真实而格外动人。', NULL, 59, NULL, 10, 0, 0, 0, 0, NULL, NULL, '2026-04-06 21:17:03', 1);
